  createComment,
  NotFoundError,
  ForeignKeyError,
} from '../db/queries.js';
```

**Import note**: The test file is at `server/test/db.test.mjs`. The import path `../db/queries.js` is relative to `server/test/`, resolving to `server/db/queries.js`. This is correct.

---

### Describe Block 1: `initDb and closeDb`

**before**: nothing (no shared state)

