### Custom Error Classes

```javascript
export class NotFoundError extends Error {
  constructor(message) {
    super(message);
    this.name = 'NotFoundError';
  }
}

export class DatabaseError extends Error {
  constructor(message) {
    super(message);
    this.name = 'DatabaseError';
  }
}

export class ForeignKeyError extends DatabaseError {
  constructor(message) {
    super(message);
    this.name = 'ForeignKeyError';
  }
}
```

**Note on ForeignKeyError**: `better-sqlite3` throws a generic `Error` with code `SQLITE_CONSTRAINT_FOREIGNKEY` when a FK violation occurs. The `createComment` function must catch this and re-throw as `ForeignKeyError`. The test must import and check `instanceof ForeignKeyError`.

### `initDb(dbPath?)`

```javascript
export function initDb(dbPath = 'data/kanban.db') {
  const resolvedPath = dbPath === ':memory:' ? ':memory:' : resolve(process.cwd(), dbPath);
  db = new Database(resolvedPath);

  db.pragma('journal_mode = WAL');
  db.pragma('foreign_keys = ON');

  const migration = readFileSync(
    resolve(__dirname, 'migrations', '001_init.sql'),
    'utf8'
  );
  db.exec(migration);

  // Prepare cached statements
  stmts.getAllCards = db.prepare(
    'SELECT * FROM cards ORDER BY "column", position'
  );
  stmts.getAllComments = db.prepare(
    'SELECT * FROM comments ORDER BY created_at'
  );
  stmts.insertCard = db.prepare(
    'INSERT INTO cards (id, title, assignee, "column", position, description, created_at) VALUES (@id, @title, @assignee, @column, @position, @description, @created_at)'
  );
  stmts.getCardById = db.prepare('SELECT * FROM cards WHERE id = ?');
  stmts.maxPositionInColumn = db.prepare(
    'SELECT MAX(position) as maxPos FROM cards WHERE "column" = ?'
  );
  stmts.deleteCard = db.prepare('DELETE FROM cards WHERE id = ?');
  stmts.insertComment = db.prepare(
    'INSERT INTO comments (id, card_id, author, content, created_at) VALUES (@id, @card_id, @author, @content, @created_at)'
  );
  stmts.getCommentById = db.prepare('SELECT * FROM comments WHERE id = ?');
  stmts.getSiblingsInColumn = db.prepare(
    'SELECT id, position FROM cards WHERE "column" = ? AND id != ? ORDER BY position'
  );
  stmts.updateCardColumn = db.prepare(
    'UPDATE cards SET "column" = @column, position = @position WHERE id = @id'
  );

  return db;
}
```

**Critical detail**: `column` is a reserved word in SQLite. It must be quoted with double-quotes in all SQL strings: `"column"`. The `@param` named-binding syntax is used for INSERT (vs `?` positional for simple lookups).

### `closeDb()`

```javascript
export function closeDb() {
  if (db) {
    db.close();
    db = null;
    stmts = {};
  }
}
```

### `getCards()`

```javascript
export function getCards() {
  const cards = stmts.getAllCards.all();
  const comments = stmts.getAllComments.all();

  // Group comments by card_id
  const commentsByCardId = {};
  for (const comment of comments) {
    if (!commentsByCardId[comment.card_id]) {
      commentsByCardId[comment.card_id] = [];
    }
    commentsByCardId[comment.card_id].push(comment);
  }

  return cards.map(card => ({
    ...card,
    comments: commentsByCardId[card.id] ?? [],
  }));
}
```

**Two separate queries**, not a JOIN: this avoids the N-row cartesian expansion problem when cards have multiple comments and preserves ordering guarantees independently.

### `createCard(data)`

```javascript
export function createCard(data) {
  const { title, assignee = null, column = 'ready', description = null } = data;

  const id = uuidv4();
  const created_at = Date.now();

  const { maxPos } = stmts.maxPositionInColumn.get(column);
  const position = maxPos === null ? 1.0 : maxPos + 1.0;

  stmts.insertCard.run({ id, title, assignee, column, position, description, created_at });
  return stmts.getCardById.get(id);
}
```

**Position assignment**: New cards always get `max + 1.0`. This gives whole-number positions initially (1.0, 2.0, 3.0, ...) which leaves room for fractional moves between them.

### `updateCard(id, data)`

```javascript
export function updateCard(id, data) {
  const allowed = ['title', 'assignee', 'column', 'description', 'position'];
  const fields = Object.keys(data).filter(k => allowed.includes(k));
  if (fields.length === 0) {
    // Nothing to update — just return current card or throw
    const card = stmts.getCardById.get(id);
    if (!card) throw new NotFoundError(`Card not found: ${id}`);
    return card;
  }

  const setClause = fields.map(f => `"${f}" = @${f}`).join(', ');
  const stmt = db.prepare(`UPDATE cards SET ${setClause} WHERE id = @id`);
  const result = stmt.run({ ...data, id });

  if (result.changes === 0) throw new NotFoundError(`Card not found: ${id}`);
  return stmts.getCardById.get(id);
}
```

**Why dynamic prepare**: `updateCard` must support partial updates (only the fields present in `data`). Since the SET clause varies per call, the statement cannot be pre-prepared at init time. `db.prepare()` is called inline each time. The field allowlist prevents SQL injection through the field-name interpolation. Values are always passed as bound parameters (`@field`), never interpolated.

### `deleteCard(id)`

```javascript
export function deleteCard(id) {
  const result = stmts.deleteCard.run(id);
  if (result.changes === 0) throw new NotFoundError(`Card not found: ${id}`);
  return true;
}
```

Comments are deleted automatically via `ON DELETE CASCADE` (only if `foreign_keys = ON` pragma was set, which `initDb` ensures).

### `moveCard(id, column, targetIndex)` — The Core Algorithm

`targetIndex` is 0-based. Target position is computed from the sorted sibling list (excluding the card being moved).

```javascript
export function moveCard(id, column, targetIndex) {
  const card = stmts.getCardById.get(id);
  if (!card) throw new NotFoundError(`Card not found: ${id}`);

  const move = db.transaction(() => {
    const siblings = stmts.getSiblingsInColumn.all(column, id);
    // siblings is sorted by position, excludes the card being moved

    let newPosition;

    if (siblings.length === 0) {
      // Empty column (or only card is the one being moved)
      newPosition = 1.0;
    } else if (targetIndex <= 0) {
      // Insert before the first sibling
      newPosition = siblings[0].position / 2;
    } else if (targetIndex >= siblings.length) {
      // Insert after the last sibling
      newPosition = siblings[siblings.length - 1].position + 1.0;
    } else {
      // Insert between targetIndex-1 and targetIndex
      const before = siblings[targetIndex - 1].position;
      const after = siblings[targetIndex].position;
      newPosition = (before + after) / 2;
    }

    // Renormalize if gap is too small (< 0.001)
    const needsRenorm =
      targetIndex > 0 &&
      targetIndex < siblings.length &&
      siblings[targetIndex].position - siblings[targetIndex - 1].position < 0.001;

    if (needsRenorm) {
      // Reset all siblings to 1.0, 2.0, 3.0, ... then re-insert the moved card
      const renormalize = db.prepare(
        'UPDATE cards SET position = ? WHERE id = ?'
      );
      // Build new ordering: insert moved card at targetIndex among siblings
      const newOrder = [
        ...siblings.slice(0, targetIndex),
        { id },
        ...siblings.slice(targetIndex),
      ];
      newOrder.forEach((s, i) => {
        renormalize.run(i + 1.0, s.id);
      });
      newPosition = targetIndex + 1.0;
    } else {
      stmts.updateCardColumn.run({ column, position: newPosition, id });
    }

    // Final update of the moved card (covers the non-renorm path fully,
    // and the renorm path already set position via newOrder loop above)
    if (!needsRenorm) {
      stmts.updateCardColumn.run({ column, position: newPosition, id });
    }

    return stmts.getCardById.get(id);
  });

  return move();
}
```

**Corrected algorithm** (the above has a double-update bug in the non-renorm path — the implementing agent should use this cleaned version):

```
function moveCard(id, column, targetIndex):
  card = getCardById(id)  -- throw NotFoundError if null

  TRANSACTION:
    siblings = getSiblingsInColumn(column, id)  -- excludes moved card, sorted by position

    if siblings is empty:
      newPosition = 1.0
    elif targetIndex <= 0:
      newPosition = siblings[0].position / 2
    elif targetIndex >= siblings.length:
      newPosition = siblings[siblings.length - 1].position + 1.0
    else:
      before = siblings[targetIndex - 1].position
      after  = siblings[targetIndex].position
      gap    = after - before
      if gap < 0.001:
        -- RENORMALIZE entire column
        -- Build ordered list: siblings with moved card inserted at targetIndex
        newOrder = siblings[0..targetIndex-1] + [id] + siblings[targetIndex..]
        for each (item, i) in newOrder:
          UPDATE cards SET position = (i+1).0 WHERE id = item.id
        newPosition = targetIndex + 1.0  -- (already set above, just record it)
        -- No separate update needed; moved card already updated in loop
        return getCardById(id)
      else:
        newPosition = (before + after) / 2

    UPDATE cards SET column = column, position = newPosition WHERE id = id
    return getCardById(id)
  END TRANSACTION
```

**Simplification**: The renormalization case should update ALL cards in the column (including the moved card) in one pass, then return. The non-renormalization case updates only the moved card.

### `createComment(cardId, data)`

```javascript
export function createComment(cardId, data) {
  const { author, content } = data;
  const id = uuidv4();
  const created_at = Date.now();

  try {
    stmts.insertComment.run({ id, card_id: cardId, author, content, created_at });
  } catch (err) {
    if (err.code === 'SQLITE_CONSTRAINT_FOREIGNKEY') {
      throw new ForeignKeyError(`Card not found: ${cardId}`);
    }
    throw new DatabaseError(err.message);
  }

  return stmts.getCommentById.get(id);
}
```

**Note on FK error detection**: `better-sqlite3` exposes the SQLite error code on the thrown Error as `.code`. The value is `'SQLITE_CONSTRAINT_FOREIGNKEY'`. The FK pragma must be ON (set in `initDb`) for this to trigger rather than silently inserting an orphaned row.

