252	### 2b. Implementation: `moveCard` (add to queries.js)
253	
254	**Algorithm** (integer targetIndex = 0-based desired rank among siblings):
255	
256	```javascript
257	export function moveCard(id, column, targetIndex) {
258	  const card = stmts.getCardById.get(id);
259	  if (!card) throw new NotFoundError(`Card not found: ${id}`);
260	
261	  const doMove = db.transaction(() => {
262	    const siblings = stmts.getSiblings.all(column, id);
263	
264	    if (siblings.length === 0) {
265	      stmts.updateCardPos.run({ column, position: 1.0, id });
266	    } else if (targetIndex <= 0) {
267	      stmts.updateCardPos.run({ column, position: siblings[0].position / 2, id });
268	    } else if (targetIndex >= siblings.length) {
269	      stmts.updateCardPos.run({ column, position: siblings[siblings.length - 1].position + 1.0, id });
270	    } else {
271	      const before = siblings[targetIndex - 1].position;
272	      const after  = siblings[targetIndex].position;
273	      const gap    = after - before;
274	
275	      if (gap >= 0.001) {
276	        stmts.updateCardPos.run({ column, position: (before + after) / 2, id });
277	      } else {
278	        // Renormalize: build new order with moved card spliced in
279	        const renorm = db.prepare('UPDATE cards SET "column" = ?, position = ? WHERE id = ?');
280	        const newOrder = [
281	          ...siblings.slice(0, targetIndex),
282	          { id },
283	          ...siblings.slice(targetIndex),
284	        ];
285	        newOrder.forEach((s, i) => renorm.run(column, i + 1.0, s.id));
286	      }
287	    }
288	
289	    return stmts.getCardById.get(id);
290	  });
291	
292	  return doMove();
293	}
294	```
295	
296	**Key invariants**:
297	- `getSiblings` excludes the moved card (so same-column moves work without special casing)
298	- Renormalization loop handles all cards in the column, including the moved card
299	- `db.prepare()` inside transaction body is valid in better-sqlite3
300	
