318	```javascript
319	export function createComment(cardId, data) {
320	  const { author, content } = data;
321	  const id = uuidv4();
322	  const created_at = Date.now();
323	  try {
324	    stmts.insertComment.run({ id, card_id: cardId, author, content, created_at });
325	  } catch (err) {
326	    if (err.code === 'SQLITE_CONSTRAINT_FOREIGNKEY') {
327	      throw new ForeignKeyError(`Card not found: ${cardId}`);
328	    }
329	    throw new DatabaseError(err.message);
330	  }
331	  return stmts.getCommentById.get(id);
332	}
333	```
