### 1b. Implementation: `server/db/migrations/001_init.sql`

```sql
PRAGMA journal_mode = WAL;

CREATE TABLE IF NOT EXISTS cards (
  id          TEXT    PRIMARY KEY,
  title       TEXT    NOT NULL,
  assignee    TEXT,
  "column"    TEXT    NOT NULL DEFAULT 'ready',
  position    REAL    NOT NULL,
  description TEXT,
  created_at  INTEGER NOT NULL
);

CREATE TABLE IF NOT EXISTS comments (
  id         TEXT    PRIMARY KEY,
  card_id    TEXT    NOT NULL REFERENCES cards(id) ON DELETE CASCADE,
  author     TEXT    NOT NULL,
  content    TEXT    NOT NULL,
  created_at INTEGER NOT NULL
);

CREATE INDEX IF NOT EXISTS idx_cards_column_position ON cards("column", position);
CREATE INDEX IF NOT EXISTS idx_comments_card_id ON comments(card_id);
```

### 1c. Implementation: `server/db/queries.js` (CRUD part)

```javascript
import Database from 'better-sqlite3';
import { v4 as uuidv4 } from 'uuid';
import { readFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { resolve, dirname } from 'node:path';

const __dirname = dirname(fileURLToPath(import.meta.url));

// --- Custom Errors ---
export class NotFoundError extends Error {
  constructor(msg) { super(msg); this.name = 'NotFoundError'; }
}
export class DatabaseError extends Error {
  constructor(msg) { super(msg); this.name = 'DatabaseError'; }
}
export class ForeignKeyError extends DatabaseError {
  constructor(msg) { super(msg); this.name = 'ForeignKeyError'; }
}

// --- Module-level singletons ---
let db = null;
let stmts = {};

export function getDb() { return db; }

// --- initDb ---
export function initDb(dbPath = 'data/kanban.db') {
  const resolvedPath = dbPath === ':memory:' ? ':memory:' : resolve(process.cwd(), dbPath);
  db = new Database(resolvedPath);
  db.pragma('journal_mode = WAL');
  db.pragma('foreign_keys = ON');
  const sql = readFileSync(resolve(__dirname, 'migrations', '001_init.sql'), 'utf8');
  db.exec(sql);
  _prepareStatements();
  return db;
}

function _prepareStatements() {
  stmts.getAllCards     = db.prepare('SELECT * FROM cards ORDER BY "column", position');
  stmts.getAllComments  = db.prepare('SELECT * FROM comments ORDER BY created_at');
  stmts.insertCard     = db.prepare(
    'INSERT INTO cards (id, title, assignee, "column", position, description, created_at) VALUES (@id, @title, @assignee, @column, @position, @description, @created_at)'
  );
  stmts.getCardById    = db.prepare('SELECT * FROM cards WHERE id = ?');
  stmts.maxPosInCol    = db.prepare('SELECT MAX(position) AS maxPos FROM cards WHERE "column" = ?');
  stmts.deleteCard     = db.prepare('DELETE FROM cards WHERE id = ?');
  stmts.insertComment  = db.prepare(
    'INSERT INTO comments (id, card_id, author, content, created_at) VALUES (@id, @card_id, @author, @content, @created_at)'
  );
  stmts.getCommentById = db.prepare('SELECT * FROM comments WHERE id = ?');
  stmts.getSiblings    = db.prepare(
    'SELECT id, position FROM cards WHERE "column" = ? AND id != ? ORDER BY position'
  );
  stmts.updateCardPos  = db.prepare(
    'UPDATE cards SET "column" = @column, position = @position WHERE id = @id'
  );
}

export function closeDb() {
  if (db) { db.close(); db = null; stmts = {}; }
}

// --- getCards ---
export function getCards() {
  const cards = stmts.getAllCards.all();
  const comments = stmts.getAllComments.all();
  const byCard = {};
  for (const c of comments) {
    (byCard[c.card_id] ??= []).push(c);
  }
  return cards.map(card => ({ ...card, comments: byCard[card.id] ?? [] }));
}

// --- createCard ---
export function createCard(data) {
  const { title, assignee = null, column = 'ready', description = null } = data;
  const id = uuidv4();
  const created_at = Date.now();
  const { maxPos } = stmts.maxPosInCol.get(column);
  const position = maxPos === null ? 1.0 : maxPos + 1.0;
  stmts.insertCard.run({ id, title, assignee, column, position, description, created_at });
  return stmts.getCardById.get(id);
}

// --- updateCard ---
export function updateCard(id, data) {
  const allowed = ['title', 'assignee', 'column', 'description', 'position'];
  const fields = Object.keys(data).filter(k => allowed.includes(k));
  if (fields.length === 0) {
    const card = stmts.getCardById.get(id);
    if (!card) throw new NotFoundError(`Card not found: ${id}`);
    return card;
  }
  const setClause = fields.map(f => `"${f}" = @${f}`).join(', ');
  const result = db.prepare(`UPDATE cards SET ${setClause} WHERE id = @id`).run({ ...data, id });
  if (result.changes === 0) throw new NotFoundError(`Card not found: ${id}`);
  return stmts.getCardById.get(id);
}

// --- deleteCard ---
export function deleteCard(id) {
  const result = stmts.deleteCard.run(id);
  if (result.changes === 0) throw new NotFoundError(`Card not found: ${id}`);
  return true;
}
```

---

## Subtask 2: moveCard with Fractional Indexing

### 2a. Write tests first (add to db.test.mjs)

#### Describe: `moveCard` (before: `initDb(':memory:')`, after: `closeDb()`)

Each test is self-contained (creates its own cards):
- `'moves card to empty column'` — create A in ready, `moveCard(A.id, 'done', 0)`, assert `column=done, position=1.0`
- `'moves card to first position in populated column'` — B,C in done; move A to index 0; assert A.position < B.position
- `'moves card to last position in populated column'` — B,C in done; move A to index 2; assert A.position > C.position
- `'moves card to middle of column'` — B,C,D in done; move A to index 1; assert B.position < A.position < C.position
- `'returned card reflects new column and position'` — assert `result.id, result.column, typeof result.position === 'number'`
- `'same-column move to later position'` — A,B,C in ready; move A to index 2; assert order B,A,C
- `'same-column move to earlier position'` — A,B,C in ready; move C to index 0; assert order C,A,B
- `'renormalizes when gap < 0.001'` — raw insert two cards with positions 1.000 and 1.0004; move third card to index 1; assert all positions become integers (1.0, 2.0, 3.0); assert relative order preserved
- `'throws NotFoundError for non-existent card'` — try/catch, assert `err instanceof NotFoundError`
- `'negative targetIndex treated as first position'` — `moveCard(A.id, 'done', -1)`, assert A.position < B.position
- `'large targetIndex treated as last position'` — `moveCard(A.id, 'done', 99)`, assert A.position > C.position

### 2b. Implementation: `moveCard` (add to queries.js)

**Algorithm** (integer targetIndex = 0-based desired rank among siblings):

```javascript
export function moveCard(id, column, targetIndex) {
  const card = stmts.getCardById.get(id);
  if (!card) throw new NotFoundError(`Card not found: ${id}`);

  const doMove = db.transaction(() => {
    const siblings = stmts.getSiblings.all(column, id);

    if (siblings.length === 0) {
      stmts.updateCardPos.run({ column, position: 1.0, id });
    } else if (targetIndex <= 0) {
      stmts.updateCardPos.run({ column, position: siblings[0].position / 2, id });
    } else if (targetIndex >= siblings.length) {
      stmts.updateCardPos.run({ column, position: siblings[siblings.length - 1].position + 1.0, id });
    } else {
      const before = siblings[targetIndex - 1].position;
      const after  = siblings[targetIndex].position;
      const gap    = after - before;

      if (gap >= 0.001) {
        stmts.updateCardPos.run({ column, position: (before + after) / 2, id });
      } else {
        // Renormalize: build new order with moved card spliced in
        const renorm = db.prepare('UPDATE cards SET "column" = ?, position = ? WHERE id = ?');
        const newOrder = [
          ...siblings.slice(0, targetIndex),
          { id },
          ...siblings.slice(targetIndex),
        ];
        newOrder.forEach((s, i) => renorm.run(column, i + 1.0, s.id));
      }
    }

    return stmts.getCardById.get(id);
  });

  return doMove();
}
```

**Key invariants**:
- `getSiblings` excludes the moved card (so same-column moves work without special casing)
- Renormalization loop handles all cards in the column, including the moved card
- `db.prepare()` inside transaction body is valid in better-sqlite3

---

## Subtask 3: Comment Operations

### 3a. Write tests first (add to db.test.mjs)

#### Describe: `createComment` (before: `initDb(':memory:')` + create card, after: `closeDb()`)
- `'returns comment with all fields'` — assert id, card_id, author, content, created_at
- `'generates UUID v4 for comment id'` — regex match
- `'sets created_at to recent timestamp'`
- `'comment appears nested in getCards()'` — assert `card.comments.length === 1`
- `'multiple comments accumulate'` — create 3 comments, assert `comments.length === 3`
- `'throws ForeignKeyError for non-existent cardId'` — try/catch, assert `err instanceof ForeignKeyError`
- `'ForeignKeyError is instanceof DatabaseError'`

### 3b. Implementation: `createComment` (add to queries.js)

```javascript
export function createComment(cardId, data) {
  const { author, content } = data;
  const id = uuidv4();
  const created_at = Date.now();
  try {
    stmts.insertComment.run({ id, card_id: cardId, author, content, created_at });
  } catch (err) {
    if (err.code === 'SQLITE_CONSTRAINT_FOREIGNKEY') {
      throw new ForeignKeyError(`Card not found: ${cardId}`);
    }
    throw new DatabaseError(err.message);
  }
  return stmts.getCommentById.get(id);
}
```

---

## Subtask 4: Prepared Statements

All queries are already prepared statements in the design above. The `updateCard` function cannot pre-prepare (dynamic SET clause), so it calls `db.prepare()` inline per call — this is intentional and safe (better-sqlite3 `prepare` is fast).

No additional work needed beyond verifying the statement cache in `_prepareStatements()` covers all hot paths.

---

## Subtask 5: Error Handling

### Error classes (in queries.js)
```javascript
export class NotFoundError extends Error { ... }     // card/comment not found
export class DatabaseError extends Error { ... }      // generic DB error
export class ForeignKeyError extends DatabaseError { ... }  // FK violation
```

### Error handling tests (add to db.test.mjs)

#### Describe: `Error Classes`
- `'NotFoundError is instanceof Error'` — assert name, message, instanceof
- `'ForeignKeyError is instanceof DatabaseError and Error'` — assert hierarchy

### Where errors are thrown
| Function | Condition | Error type |
|---|---|---|
| `updateCard` | `changes === 0` | `NotFoundError` |
| `deleteCard` | `changes === 0` | `NotFoundError` |
| `moveCard` | card not found | `NotFoundError` |
| `createComment` | FK violation | `ForeignKeyError` |
| `createComment` | other DB error | `DatabaseError` |

