158	### 1c. Implementation: `server/db/queries.js` (CRUD part)
159	
160	```javascript
161	import Database from 'better-sqlite3';
162	import { v4 as uuidv4 } from 'uuid';
163	import { readFileSync } from 'node:fs';
164	import { fileURLToPath } from 'node:url';
165	import { resolve, dirname } from 'node:path';
166	
167	const __dirname = dirname(fileURLToPath(import.meta.url));
168	
169	// --- Custom Errors ---
170	export class NotFoundError extends Error {
171	  constructor(msg) { super(msg); this.name = 'NotFoundError'; }
172	}
173	export class DatabaseError extends Error {
174	  constructor(msg) { super(msg); this.name = 'DatabaseError'; }
175	}
176	export class ForeignKeyError extends DatabaseError {
177	  constructor(msg) { super(msg); this.name = 'ForeignKeyError'; }
178	}
179	
180	// --- Module-level singletons ---
181	let db = null;
182	let stmts = {};
183	
184	export function getDb() { return db; }
185	
186	// --- initDb ---
187	export function initDb(dbPath = 'data/kanban.db') {
188	  const resolvedPath = dbPath === ':memory:' ? ':memory:' : resolve(process.cwd(), dbPath);
189	  db = new Database(resolvedPath);
190	  db.pragma('journal_mode = WAL');
191	  db.pragma('foreign_keys = ON');
192	  const sql = readFileSync(resolve(__dirname, 'migrations', '001_init.sql'), 'utf8');
193	  db.exec(sql);
194	  _prepareStatements();
195	  return db;
196	}
197	
198	function _prepareStatements() {
199	  stmts.getAllCards     = db.prepare('SELECT * FROM cards ORDER BY "column", position');
200	  stmts.getAllComments  = db.prepare('SELECT * FROM comments ORDER BY created_at');
201	  stmts.insertCard     = db.prepare(
202	    'INSERT INTO cards (id, title, assignee, "column", position, description, created_at) VALUES (@id, @title, @assignee, @column, @position, @description, @created_at)'
203	  );
204	  stmts.getCardById    = db.prepare('SELECT * FROM cards WHERE id = ?');
205	  stmts.maxPosInCol    = db.prepare('SELECT MAX(position) AS maxPos FROM cards WHERE "column" = ?');
206	  stmts.deleteCard     = db.prepare('DELETE FROM cards WHERE id = ?');
207	  stmts.insertComment  = db.prepare(
208	    'INSERT INTO comments (id, card_id, author, content, created_at) VALUES (@id, @card_id, @author, @content, @created_at)'
209	  );
210	  stmts.getCommentById = db.prepare('SELECT * FROM comments WHERE id = ?');
211	  stmts.getSiblings    = db.prepare(
212	    'SELECT id, position FROM cards WHERE "column" = ? AND id != ? ORDER BY position'
213	  );
214	  stmts.updateCardPos  = db.prepare(
215	    'UPDATE cards SET "column" = @column, position = @position WHERE id = @id'
216	  );
217	}
218	
219	export function closeDb() {
220	  if (db) { db.close(); db = null; stmts = {}; }
221	}
222	
223	// --- getCards ---
224	export function getCards() {
225	  const cards = stmts.getAllCards.all();
226	  const comments = stmts.getAllComments.all();
227	  const byCard = {};
228	  for (const c of comments) {
229	    (byCard[c.card_id] ??= []).push(c);
230	  }
231	  return cards.map(card => ({ ...card, comments: byCard[card.id] ?? [] }));
232	}
233	
234	// --- createCard ---
235	export function createCard(data) {
236	  const { title, assignee = null, column = 'ready', description = null } = data;
237	  const id = uuidv4();
238	  const created_at = Date.now();
239	  const { maxPos } = stmts.maxPosInCol.get(column);
240	  const position = maxPos === null ? 1.0 : maxPos + 1.0;
241	  stmts.insertCard.run({ id, title, assignee, column, position, description, created_at });
242	  return stmts.getCardById.get(id);
243	}
244	
245	// --- updateCard ---
246	export function updateCard(id, data) {
247	  const allowed = ['title', 'assignee', 'column', 'description', 'position'];
248	  const fields = Object.keys(data).filter(k => allowed.includes(k));
249	  if (fields.length === 0) {
250	    const card = stmts.getCardById.get(id);
251	    if (!card) throw new NotFoundError(`Card not found: ${id}`);
252	    return card;
253	  }
254	  const setClause = fields.map(f => `"${f}" = @${f}`).join(', ');
255	  const result = db.prepare(`UPDATE cards SET ${setClause} WHERE id = @id`).run({ ...data, id });
256	  if (result.changes === 0) throw new NotFoundError(`Card not found: ${id}`);
257	  return stmts.getCardById.get(id);
258	}
259	
260	// --- deleteCard ---
261	export function deleteCard(id) {
262	  const result = stmts.deleteCard.run(id);
263	  if (result.changes === 0) throw new NotFoundError(`Card not found: ${id}`);
264	  return true;
265	}
266	```
