170	**Note**: Do NOT include `PRAGMA` statements in the SQL file. Pragmas are set programmatically in `initDb()` via `db.pragma()` before `db.exec()` is called. Mixing pragmas into migration SQL causes confusion and can misbehave if `db.exec` processes them in unexpected order.
171	
172	### 1c. Implementation: `server/db/queries.js` (CRUD part)
173	
174	```javascript
175	import Database from 'better-sqlite3';
176	import { v4 as uuidv4 } from 'uuid';
177	import { readFileSync, mkdirSync } from 'node:fs';
178	import { fileURLToPath } from 'node:url';
179	import { resolve, dirname } from 'node:path';
180	
181	const __dirname = dirname(fileURLToPath(import.meta.url));
182	
183	// --- Custom Errors ---
184	export class NotFoundError extends Error {
185	  constructor(msg) { super(msg); this.name = 'NotFoundError'; }
186	}
187	export class DatabaseError extends Error {
188	  constructor(msg) { super(msg); this.name = 'DatabaseError'; }
189	}
190	export class ForeignKeyError extends DatabaseError {
191	  constructor(msg) { super(msg); this.name = 'ForeignKeyError'; }
192	}
193	
194	// --- Module-level singletons ---
195	let db = null;
196	let stmts = {};
197	
198	export function getDb() { return db; }
199	
200	// --- initDb ---
201	export function initDb(dbPath = 'data/kanban.db') {
202	  const resolvedPath = dbPath === ':memory:' ? ':memory:' : resolve(process.cwd(), dbPath);
203	  if (dbPath !== ':memory:') {
204	    mkdirSync(dirname(resolvedPath), { recursive: true });
205	  }
206	  db = new Database(resolvedPath);
207	  db.pragma('journal_mode = WAL');
208	  db.pragma('foreign_keys = ON');
209	  const sql = readFileSync(resolve(__dirname, 'migrations', '001_init.sql'), 'utf8');
210	  db.exec(sql);
211	  _prepareStatements();
212	  return db;
213	}
214	
215	function _prepareStatements() {
216	  stmts.getAllCards     = db.prepare('SELECT * FROM cards ORDER BY "column", position');
217	  stmts.getAllComments  = db.prepare('SELECT * FROM comments ORDER BY created_at');
218	  stmts.insertCard     = db.prepare(
219	    'INSERT INTO cards (id, title, assignee, "column", position, description, created_at) VALUES (@id, @title, @assignee, @column, @position, @description, @created_at)'
220	  );
221	  stmts.getCardById    = db.prepare('SELECT * FROM cards WHERE id = ?');
222	  stmts.maxPosInCol    = db.prepare('SELECT MAX(position) AS maxPos FROM cards WHERE "column" = ?');
223	  stmts.deleteCard     = db.prepare('DELETE FROM cards WHERE id = ?');
224	  stmts.insertComment  = db.prepare(
225	    'INSERT INTO comments (id, card_id, author, content, created_at) VALUES (@id, @card_id, @author, @content, @created_at)'
226	  );
227	  stmts.getCommentById = db.prepare('SELECT * FROM comments WHERE id = ?');
228	  stmts.getSiblings    = db.prepare(
229	    'SELECT id, position FROM cards WHERE "column" = ? AND id != ? ORDER BY position'
230	  );
231	  stmts.updateCardPos  = db.prepare(
232	    'UPDATE cards SET "column" = @column, position = @position WHERE id = @id'
233	  );
234	}
235	
236	export function closeDb() {
237	  if (db) { db.close(); db = null; stmts = {}; }
238	}
239	
240	// --- getCards ---
241	export function getCards() {
242	  const cards = stmts.getAllCards.all();
243	  const comments = stmts.getAllComments.all();
244	  const byCard = {};
245	  for (const c of comments) {
246	    (byCard[c.card_id] ??= []).push(c);
247	  }
248	  return cards.map(card => ({ ...card, comments: byCard[card.id] ?? [] }));
249	}
250	
251	// --- createCard ---
252	export function createCard(data) {
253	  const { title, assignee = null, column = 'ready', description = null } = data;
254	  const id = uuidv4();
255	  const created_at = Date.now();
256	  const { maxPos } = stmts.maxPosInCol.get(column);
257	  const position = maxPos === null ? 1.0 : maxPos + 1.0;
258	  stmts.insertCard.run({ id, title, assignee, column, position, description, created_at });
259	  return stmts.getCardById.get(id);
260	}
261	
262	// --- updateCard ---
263	export function updateCard(id, data) {
264	  const allowed = ['title', 'assignee', 'column', 'description', 'position'];
265	  const fields = Object.keys(data).filter(k => allowed.includes(k));
266	  if (fields.length === 0) {
267	    const card = stmts.getCardById.get(id);
268	    if (!card) throw new NotFoundError(`Card not found: ${id}`);
269	    return card;
270	  }
271	  const setClause = fields.map(f => `"${f}" = @${f}`).join(', ');
272	  const result = db.prepare(`UPDATE cards SET ${setClause} WHERE id = @id`).run({ ...data, id });
273	  if (result.changes === 0) throw new NotFoundError(`Card not found: ${id}`);
274	  return stmts.getCardById.get(id);
275	}
276	
277	// --- deleteCard ---
278	export function deleteCard(id) {
279	  const result = stmts.deleteCard.run(id);
280	  if (result.changes === 0) throw new NotFoundError(`Card not found: ${id}`);
281	  return true;
282	}
283	```
284	
285	---
286	
287	## Subtask 2: moveCard with Fractional Indexing
288	
289	### Function signature clarification
290	
291	The task specifies `moveCard(id, column, position)`. The `position` parameter here is an **integer 0-based target index** (not a floating-point fractional value). The function computes the fractional position value internally using the sibling list. The parameter is named `position` in the exported API to match the task spec.
292	
293	### 2a. Write tests first (add to db.test.mjs)
294	
295	#### Describe: `moveCard` (beforeEach: `initDb(':memory:')`, afterEach: `closeDb()`)
296	
297	Each test is self-contained (creates its own cards within the test body):
298	
299	- `'moves card to empty column'` — create A in 'ready'; `moveCard(A.id, 'done', 0)`; assert `result.column === 'done'` and `result.position === 1.0`
300	
301	- `'moves card to first position in populated column'` — create B and C in 'done' (B gets pos 1.0, C gets 2.0); create A in 'ready'; capture `const result = moveCard(A.id, 'done', 0)`; assert `result.id === A.id`, `result.column === 'done'`, and `result.position < B.position` (B.position from the createCard snapshot = 1.0; result.position = 0.5). **Important**: use `result.position`, NOT `A.position` — `A` is the stale createCard snapshot and its `.position` is still the 'ready' column value.
302	
303	- `'moves card to last position in populated column'` — create B(1.0) and C(2.0) in 'done'; create A in 'ready'; capture `const result = moveCard(A.id, 'done', 2)` (position=2 >= 2 siblings → after last); assert `result.position > C.position` (C.position=2.0; result.position=3.0). Use `result.position`, not `A.position`.
304	
305	- `'moves card to middle position in column'` — create B(1.0), C(2.0), D(3.0) in 'done'; create A in 'ready'; capture `const result = moveCard(A.id, 'done', 1)` (between B and C); assert `B.position < result.position && result.position < C.position` (B=1.0, result=1.5, C=2.0). Use `result.position`, not `A.position`.
306	
307	- `'returned card reflects updated column and position'` — create A in 'ready'; `const result = moveCard(A.id, 'done', 0)`; assert `result.id === A.id`, `result.column === 'done'`, `typeof result.position === 'number'`
308	
309	- `'moves card within same column to later position'` — create A(1.0), B(2.0), C(3.0) all in 'ready'; `moveCard(A.id, 'ready', 1)` → siblings=[B(2.0),C(3.0)], inserts between B and C giving A position 2.5; verify by fetching `getCards().filter(c => c.column === 'ready').sort((a,b) => a.position - b.position)` and asserting `sorted[0].id === B.id`, `sorted[1].id === A.id`, `sorted[2].id === C.id`. Do NOT compare `A.position` directly — `A` is the stale createCard snapshot; use the sorted array IDs instead.
310	
311	- `'moves card within same column to earlier position'` — create A(1.0), B(2.0), C(3.0) in 'ready'; `moveCard(C.id, 'ready', 0)` → before A; assert order is C, A, B
312	
313	- `'renormalizes column when position gap falls below 0.001'` — raw-insert two cards with near-identical positions, then move a third card between them and verify renormalization fires. Exact setup:
314	  ```javascript
315	  const db = getDb();
316	  const insertCard = db.prepare(
317	    'INSERT INTO cards (id, title, "column", position, created_at) VALUES (?, ?, ?, ?, ?)'
318	  );
319	  insertCard.run('renorm-1', 'Card One', 'renorm_test', 1.0,    1000);
320	  insertCard.run('renorm-2', 'Card Two', 'renorm_test', 1.0004, 2000);
321	  const A = createCard({ title: 'A', column: 'ready' });
322	  moveCard(A.id, 'renorm_test', 1); // gap 0.0004 < 0.001 → renormalize
323	  const cards = getCards()
324	    .filter(c => c.column === 'renorm_test')
325	    .sort((a, b) => a.position - b.position);
326	  // Assert all positions are whole numbers (renorm assigns 1.0, 2.0, 3.0)
327	  for (const c of cards) assert.ok(c.position % 1 === 0, `position ${c.position} is not whole`);
328	  // Assert relative order preserved: renorm-1 still before renorm-2
329	  const r1 = cards.find(c => c.id === 'renorm-1');
330	  const r2 = cards.find(c => c.id === 'renorm-2');
331	  assert.ok(r1.position < r2.position);
332	  ```
333	
334	- `'throws NotFoundError for a non-existent card id'` — `try { moveCard('no-such-id', 'ready', 0) } catch(e) { assert.ok(e instanceof NotFoundError) }`
335	
336	- `'negative position value treated as first position'` — create B in 'done' (pos 1.0); create A in 'ready'; capture `const result = moveCard(A.id, 'done', -5)`; assert `result.position < B.position` (result.position=0.5, B.position=1.0). Use `result.position`, not `A.position`.
337	
338	- `'position beyond end treated as last position'` — create B(1.0) and C(2.0) in 'done'; create A in 'ready'; capture `const result = moveCard(A.id, 'done', 999)`; assert `result.position > C.position` (result.position=3.0, C.position=2.0). Use `result.position`, not `A.position`.
339	
340	### 2b. Implementation: `moveCard` (add to queries.js)
341	
342	The `position` parameter is the integer 0-based target rank among siblings (cards in the target column excluding the moved card):
343	
344	```javascript
345	export function moveCard(id, column, position) {
346	  const card = stmts.getCardById.get(id);
347	  if (!card) throw new NotFoundError(`Card not found: ${id}`);
348	
349	  const doMove = db.transaction(() => {
350	    const siblings = stmts.getSiblings.all(column, id);
351	    // siblings: sorted by position, excludes the moved card itself
352	
353	    if (siblings.length === 0) {
354	      stmts.updateCardPos.run({ column, position: 1.0, id });
355	    } else if (position <= 0) {
356	      stmts.updateCardPos.run({ column, position: siblings[0].position / 2, id });
357	    } else if (position >= siblings.length) {
358	      stmts.updateCardPos.run({ column, position: siblings[siblings.length - 1].position + 1.0, id });
359	    } else {
360	      const before = siblings[position - 1].position;
361	      const after  = siblings[position].position;
362	      const gap    = after - before;
363	
364	      if (gap >= 0.001) {
365	        stmts.updateCardPos.run({ column, position: (before + after) / 2, id });
366	      } else {
367	        // Renormalize: splice moved card into siblings at the target index, then
368	        // assign clean integer positions (1.0, 2.0, 3.0, ...) to all cards in column
369	        const renorm = db.prepare('UPDATE cards SET "column" = ?, position = ? WHERE id = ?');
370	        const newOrder = [
371	          ...siblings.slice(0, position),
372	          { id },
373	          ...siblings.slice(position),
374	        ];
375	        newOrder.forEach((s, i) => renorm.run(column, i + 1.0, s.id));
376	      }
377	    }
378	
379	    return stmts.getCardById.get(id);
380	  });
381	
382	  return doMove();
383	}
384	```
385	
386	**Key invariants**:
387	- `getSiblings` excludes the moved card — same-column and cross-column moves use identical logic
388	- In the renormalization path, `newOrder` includes all siblings plus the moved card at the target index; the loop updates every card in the column (including the moved card) to a clean integer position
389	- `db.prepare()` inside the transaction callback is valid in better-sqlite3 (only `.run()` calls are transactional)
390	- No special case needed for same-column moves; `getSiblings` handles exclusion automatically
391	
392	---
393	
394	## Subtask 3: Comment Operations
395	
396	### 3a. Write tests first (add to db.test.mjs)
397	
398	#### Describe: `createComment` (beforeEach: `initDb(':memory:')` + `createCard(...)`, afterEach: `closeDb()`)
399	
400	```javascript
401	describe('createComment', () => {
402	  let cardId;
403	  beforeEach(() => {
404	    initDb(':memory:');
405	    cardId = createCard({ title: 'Parent card' }).id;
406	  });
407	  afterEach(() => closeDb());
408	  // ...tests...
409	});
410	```
411	
412	- `'returns comment with all fields'` — `createComment(cardId, { author: 'Alice', content: 'Hello' })` → assert `comment.id`, `comment.card_id === cardId`, `comment.author === 'Alice'`, `comment.content === 'Hello'`, `typeof comment.created_at === 'number'`
413	- `'generates a valid UUID v4 for comment id'` — assert matches `/^[0-9a-f]{8}-[0-9a-f]{4}-4[0-9a-f]{3}-[89ab][0-9a-f]{3}-[0-9a-f]{12}$/`
414	- `'sets created_at to a recent timestamp'` — record `t0 = Date.now()`, create comment, record `t1 = Date.now()`; assert `comment.created_at >= t0 && comment.created_at <= t1`
415	- `'comment appears nested under the card in getCards()'` — create comment; `getCards()` → find card by id; assert `card.comments.length === 1` and `card.comments[0].content === 'Hello'`
416	- `'multiple comments accumulate under the card'` — create 3 comments; `getCards()` → find card → assert `card.comments.length === 3`
417	- `'throws ForeignKeyError for a non-existent cardId'` — `try { createComment('no-such-card', { author: 'X', content: 'Y' }) } catch(e) { assert.ok(e instanceof ForeignKeyError) }`
418	- `'ForeignKeyError is also an instance of DatabaseError'` — catch error from non-existent cardId; assert `e instanceof DatabaseError`
419	
420	### 3b. Implementation: `createComment` (add to queries.js)
421	
422	```javascript
423	export function createComment(cardId, data) {
424	  const { author, content } = data;
425	  const id = uuidv4();
426	  const created_at = Date.now();
427	  try {
428	    stmts.insertComment.run({ id, card_id: cardId, author, content, created_at });
429	  } catch (err) {
430	    if (err.code === 'SQLITE_CONSTRAINT_FOREIGNKEY') {
431	      throw new ForeignKeyError(`Card not found: ${cardId}`);
432	    }
433	    throw new DatabaseError(err.message);
434	  }
435	  return stmts.getCommentById.get(id);
436	}
437	```
438	
439	**Note**: The FK constraint only fires if `PRAGMA foreign_keys = ON` is active. `initDb()` sets this before running migrations. The error code `'SQLITE_CONSTRAINT_FOREIGNKEY'` is exposed as `err.code` by better-sqlite3.
440	
441	---
442	
443	## Subtask 4: Prepared Statements
444	
445	All hot-path queries are pre-cached in `_prepareStatements()` called at the end of `initDb()`. The `updateCard` function cannot be pre-prepared because its SET clause is dynamically constructed from `Object.keys(data)`. It calls `db.prepare()` inline on each invocation — this is intentional and safe (better-sqlite3's `prepare` is very fast).
446	
447	No additional work needed beyond verifying `_prepareStatements()` covers all functions except `updateCard` and the inline renormalization `prepare` inside `moveCard`.
448	
449	---
450	
451	## Subtask 5: Error Handling
452	
453	### Error classes (in queries.js)
454	```javascript
455	export class NotFoundError extends Error { ... }          // card not found by id
456	export class DatabaseError extends Error { ... }           // generic DB failure
457	export class ForeignKeyError extends DatabaseError { ... } // FK constraint violated
458	```
459	
460	### Error handling tests (add to db.test.mjs)
461	
462	#### Describe: `Error Classes` (no DB needed, no beforeEach/afterEach)
463	- `'NotFoundError is instanceof Error with correct name and message'` — `const e = new NotFoundError('test msg')`; assert `e instanceof Error`, `e.name === 'NotFoundError'`, `e.message === 'test msg'`
464	- `'ForeignKeyError is instanceof DatabaseError and Error'` — `const e = new ForeignKeyError('fk')`; assert `e instanceof ForeignKeyError`, `e instanceof DatabaseError`, `e instanceof Error`, `e.name === 'ForeignKeyError'`
465	
466	### Where errors are thrown
467	
468	| Function | Condition | Error type |
469	|---|---|---|
470	| `updateCard` | `changes === 0` after UPDATE | `NotFoundError` |
471	| `updateCard` | empty `fields` + card not found | `NotFoundError` |
472	| `deleteCard` | `changes === 0` after DELETE | `NotFoundError` |
473	| `moveCard` | `getCardById` returns null | `NotFoundError` |
474	| `createComment` | `err.code === 'SQLITE_CONSTRAINT_FOREIGNKEY'` | `ForeignKeyError` |
475	| `createComment` | any other DB error | `DatabaseError` |
476	
477	---
478	
479	## Critical Implementation Notes
480	
481	1. **`column` is a reserved word in SQLite** — quote it as `"column"` in ALL SQL strings in queries.js (SELECT, INSERT, UPDATE, WHERE, ORDER BY, CREATE TABLE, CREATE INDEX). Missing a single quote causes a runtime syntax error.
482	
483	2. **`db.pragma()` returns arrays by default** — when asserting a scalar value from a pragma call, always use the `{ simple: true }` option: `db.pragma('foreign_keys', { simple: true })` returns `1`, while `db.pragma('foreign_keys')` returns `[{ foreign_keys: 1 }]`.
484	
485	3. **WAL mode on `:memory:` databases** — `PRAGMA journal_mode = WAL` silently stays as `'memory'` for in-memory databases (SQLite does not support WAL on in-memory DBs). Do not assert the resulting mode in tests. The `initDb` call should not throw.
486	
487	4. **FK enforcement requires pragma** — `PRAGMA foreign_keys = ON` in `initDb` is mandatory. Without it: (a) `ON DELETE CASCADE` does nothing, (b) inserting a comment with a non-existent `card_id` silently succeeds instead of throwing. All cascade and FK tests depend on this pragma being set.
488	
489	5. **`assert.throws` + instanceof** — `assert.throws(fn, MyErrorClass)` does NOT check `instanceof` in Node's `assert/strict`. To test for a specific error class, use try/catch: `try { fn() } catch(e) { assert.ok(e instanceof MyClass) }`. Or use `assert.throws(fn, { name: 'ClassName' })` which checks `err.name`.
490	
491	6. **`getDb()` export** — needed for the cascade-delete test (5.5) to directly query the `comments` table, and for the renormalization test (6.8) to raw-insert cards with specific positions.
492	
493	7. **Named params vs positional** — use `@name` style with object binding for INSERT/UPDATE statements; use `?` positional for simple lookups (getCardById, deleteCard, etc.). Do not mix styles within one `.prepare()` statement.
494	
495	8. **`moveCard` `position` parameter semantics** — The exported function is `moveCard(id, column, position)` where `position` is an integer 0-based target index (the slot where the moved card should end up among its siblings after the move). It is NOT a fractional float value; that is computed internally.
496	
497	9. **Stale card snapshots in tests** — `createCard()` and `moveCard()` return plain row objects. After calling `moveCard(A.id, ...)`, the original `A` variable still holds the pre-move position. Always use `moveCard`'s return value (e.g. `const result = moveCard(...)`) or re-fetch via `getCards()` when asserting the moved card's new position. Only sibling cards (B, C, D) that were NOT moved retain valid stale positions.
498	
499	---
500	
501	## Verification
502	
503	After implementation, from the `server/` directory:
504	
505	```bash
506	# Run DB tests
507	node --test test/db.test.mjs
508	
509	# Run all server tests
510	node --test test/server.test.mjs test/db.test.mjs
511	
512	# Basic smoke test (from server/ directory)
513	node -e "
514	import('./db/queries.js').then(({ initDb, getCards, createCard, createComment }) => {
515	  initDb(':memory:');
516	  const card = createCard({ title: 'Smoke test' });
517	  createComment(card.id, { author: 'Tester', content: 'Works!' });
518	  console.log(JSON.stringify(getCards(), null, 2));
519	});
520	"
521	```
522	
523	Expected output for smoke test: a JSON array containing one card with one nested comment.
