    initDb(':memory:');
    const result = getDb().prepare("SELECT name FROM sqlite_master WHERE type='table' AND name='comments'").get();
    assert.equal(result.name, 'comments');
    closeDb();
  });

  it('initDb enables foreign keys', () => {
